from dataclasses import dataclass

@dataclass
class ToilCandidate:
    name: str
    monthly_hours: float    # hours/month currently consumed
    automation_score: int   # 1=hard to automate, 5=easy to automate
    growth_score: int       # 1=fixed cost, 5=scales linearly with traffic
    automation_cost_hours: float  # estimated one-time engineering cost to automate

    @property
    def monthly_value(self) -> float:
        """Score: hours_saved * automation_feasibility * growth_risk."""
        return self.monthly_hours * self.automation_score * self.growth_score

    @property
    def payback_months(self) -> float:
        """How many months until automation investment pays off."""
        if self.monthly_hours == 0:
            return float("inf")
        return self.automation_cost_hours / self.monthly_hours


def prioritize(candidates: list[ToilCandidate]) -> list[ToilCandidate]:
    return sorted(candidates, key=lambda c: c.monthly_value, reverse=True)


# Example prioritization
candidates = [
    ToilCandidate("prompt_tweaking",           monthly_hours=42,  automation_score=3, growth_score=4, automation_cost_hours=80),
    ToilCandidate("runbook_execution",          monthly_hours=38,  automation_score=5, growth_score=5, automation_cost_hours=60),
    ToilCandidate("context_window_management", monthly_hours=29,  automation_score=5, growth_score=5, automation_cost_hours=40),
    ToilCandidate("on_call_interrupt",          monthly_hours=21,  automation_score=2, growth_score=3, automation_cost_hours=120),
    ToilCandidate("ticket_triage",             monthly_hours=18,  automation_score=4, growth_score=3, automation_cost_hours=50),
]

ranked = prioritize(candidates)
for i, c in enumerate(ranked, 1):
    print(f"{i}. {c.name}: score={c.monthly_value:.0f}, payback={c.payback_months:.1f} months")

