# Agent-mediated runbook execution
# Reduces manual runbook toil by automating known step sequences

import anthropic
import json

client = anthropic.Anthropic()

tools = [
    {
        "name": "check_service_health",
        "description": "Check the health endpoint of a named service and return status",
        "input_schema": {
            "type": "object",
            "properties": {
                "service_name": {"type": "string", "description": "Service identifier"},
            },
            "required": ["service_name"]
        }
    },
    {
        "name": "restart_service",
        "description": "Restart a service. Only use for services listed in the runbook.",
        "input_schema": {
            "type": "object",
            "properties": {
                "service_name": {"type": "string"},
                "reason": {"type": "string", "description": "Reason, for audit log"}
            },
            "required": ["service_name", "reason"]
        }
    },
    {
        "name": "escalate_to_human",
        "description": "Page the on-call engineer. Use when the runbook does not cover the situation.",
        "input_schema": {
            "type": "object",
            "properties": {
                "message": {"type": "string", "description": "What was found and why human judgment is needed"}
            },
            "required": ["message"]
        }
    }
]

RUNBOOK = """
Runbook: Agent Context Overflow Recovery
1. Check health of agent-service. If healthy, no action needed — escalate.
2. If unhealthy, check error logs for context overflow errors.
3. If context overflow confirmed, restart agent-service.
4. Re-check health after 60 seconds.
5. If still unhealthy after restart, escalate to human.
"""

def execute_runbook_step(tool_name: str, tool_input: dict) -> str:
    """Simulate tool execution — replace with real API calls in production."""
    if tool_name == "check_service_health":
        return json.dumps({"status": "unhealthy", "error": "context_overflow"})
    elif tool_name == "restart_service":
        return json.dumps({"success": True, "message": f"Restarted {tool_input['service_name']}"})
    elif tool_name == "escalate_to_human":
        print(f"[ESCALATION] Paging on-call: {tool_input['message']}")
        return json.dumps({"paged": True})
    return json.dumps({"error": "unknown tool"})


def run_runbook_agent(runbook: str, incident_context: str) -> None:
    messages = [{
        "role": "user",
        "content": f"Execute this runbook.\n\nRunbook:\n{runbook}\n\nIncident: {incident_context}"
    }]

    while True:
        response = client.messages.create(
            model="claude-sonnet-4-5",
            max_tokens=2048,
            tools=tools,
            messages=messages
        )

        if response.stop_reason == "end_turn":
            print("Runbook execution complete.")
            for block in response.content:
                if hasattr(block, "text"):
                    print(f"Agent: {block.text}")
            break

        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                print(f"[TOOL] {block.name}({json.dumps(block.input)})")
                result = execute_runbook_step(block.name, block.input)
                print(f"[RESULT] {result}")
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": result
                })

        messages.append({"role": "assistant", "content": response.content})
        messages.append({"role": "user", "content": tool_results})


run_runbook_agent(RUNBOOK, "agent-service showing context overflow errors")
